target triple = "wasm32-unknown-unknown"

define <4 x i32> @dot_one_negative() {
  %res = tail call <4 x i32> @llvm.wasm.dot(<8 x i16> splat (i16 1), <8 x i16> splat (i16 -1))
  ret <4 x i32> %res
}

